class LRUCache {
private:
    struct Node {
        int key, val;
        Node* prev;
        Node* next;
        Node(int k, int v) : key(k), val(v), prev(nullptr), next(nullptr) {}
    };

    unordered_map<int, Node*> mp;
    Node* head;
    Node* tail;
    int capacity;

    void addNode(Node* node) {
        node->next = head->next;
        node->prev = head;
        head->next->prev = node;
        head->next = node;
    }

    void removeNode(Node* node) {
        node->prev->next = node->next;
        node->next->prev = node->prev;
    }

    void moveToFront(Node* node) {
        removeNode(node);
        addNode(node);
    }

public:
    LRUCache(int capacity) : capacity(capacity) {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }

    int get(int key) {
        if (!mp.count(key)) return -1;
        moveToFront(mp[key]);
        return mp[key]->val;
    }

    void put(int key, int value) {
        if (mp.count(key)) {
            mp[key]->val = value;
            moveToFront(mp[key]);
            return;
        }

        Node* node = new Node(key, value);
        mp[key] = node;
        addNode(node);

        if ((int)mp.size() > capacity) {
            Node* victim = tail->prev;
            removeNode(victim);
            mp.erase(victim->key);
            delete victim;
        }
    }
};

